 {"id":"rust_proxy-8tb","title":"E2E tests for Shell Completion","description":"## E2E Tests for Shell Completion

### Test Scenarios

1. **Completions Install Detects Shell**
   ```rust
   #[tokio::test]
   async fn test_completions_install_detects_shell() {
       std::env::set_var("SHELL", "/bin/zsh");
       let harness = TestHarness::new().await;

       let result = harness.run_command(&["completions", "install", "--dry-run"]);
       assert!(result.success);
       assert!(result.stdout.contains("Detected shell: zsh"));
   }
   ```

2. **Completions Install Creates File**
   ```rust
   #[tokio::test]
   async fn test_completions_install_creates_file() {
       let harness = TestHarness::new().await;
       let temp_dir = harness.temp_dir.path();

       let result = harness.run_command(&[
           "completions", "install",
           "--shell", "bash",
           "--path", &temp_dir.join("completions/rp").to_string_lossy()
       ]);

       assert!(result.success);
       assert!(temp_dir.join("completions/rp").exists());

       let content = fs::read_to_string(temp_dir.join("completions/rp")).unwrap();
       assert!(content.contains("complete"));
   }
   ```

3. **Completions Install --shell Override**
   ```rust
   #[tokio::test]
   async fn test_completions_install_shell_override() {
       std::env::set_var("SHELL", "/bin/zsh"); // Will be overridden
       let harness = TestHarness::new().await;

       let result = harness.run_command(&[
           "completions", "install",
           "--shell", "fish",
           "--dry-run"
       ]);

       assert!(result.success);
       assert!(result.stdout.contains("fish"));
       assert!(!result.stdout.contains("zsh"));
   }
   ```

4. **Completions Uninstall Removes File**
   ```rust
   #[tokio::test]
   async fn test_completions_uninstall() {
       let harness = TestHarness::new().await;
       let path = harness.temp_dir.path().join("rp");

       // First install
       harness.run_command(&[
           "completions", "install",
           "--shell", "bash",
           "--path", &path.to_string_lossy()
       ]);
       assert!(path.exists());

       // Then uninstall
       let result = harness.run_command(&[
           "completions", "uninstall",
           "--shell", "bash",
           "--path", &path.to_string_lossy()
       ]);

       assert!(result.success);
       assert!(!path.exists());
       assert!(result.stdout.contains("Removed"));
   }
   ```

5. **Dry-Run Shows What Would Happen**
   ```rust
   #[tokio::test]
   async fn test_completions_dry_run() {
       let harness = TestHarness::new().await;

       let result = harness.run_command(&[
           "completions", "install",
           "--shell", "bash",
           "--dry-run"
       ]);

       assert!(result.success);
       assert!(result.stdout.contains("Would install"));
       assert!(result.stdout.contains("bash"));

       // Verify no file was created
       let default_path = get_default_bash_completion_path();
       // File shouldn't be created in dry-run
   }
   ```

6. **Completions Print Outputs Script**
   ```rust
   #[tokio::test]
   async fn test_completions_print() {
       let harness = TestHarness::new().await;

       let result = harness.run_command(&["completions", "bash"]);

       assert!(result.success);
       assert!(result.stdout.contains("complete -F"));
       assert!(result.stdout.contains("_rp"));
   }
   ```

7. **Actual Completion Works in Shell**
   ```rust
   #[tokio::test]
   async fn test_completion_works_in_bash() {
       let harness = TestHarness::new().await;
       let completion_script = harness.run_command(&["completions", "bash"]).stdout;

       // Source completion in bash and test
       let bash_test = format!(r#"
           source <(echo '{}')
           # Simulate completion
           COMP_WORDS=(rp sta)
           COMP_CWORD=1
           _rp
           echo "${{COMPREPLY[@]}}"
       "#, completion_script);

       let result = Command::new("bash")
           .arg("-c")
           .arg(&bash_test)
           .output()
           .unwrap();

       let output = String::from_utf8_lossy(&result.stdout);
       assert!(output.contains("start") || output.contains("status"));
   }
   ```

### Logging Requirements
- Log detected shell and source of detection
- Log installation path being used
- Log file operations (create, overwrite, delete)
- On failure, log permission errors with suggestions

