 {"id":"rust_proxy-98d","title":"Unit tests for Systemd Service Generation","description":"## Unit Tests for Systemd Service Generation

### Test Coverage Areas

1. **Service File Template**
   ```rust
   #[test]
   fn test_service_file_has_required_sections() {
       let service = generate_service_file(&default_options());

       assert!(service.contains("[Unit]"));
       assert!(service.contains("[Service]"));
       assert!(service.contains("[Install]"));
   }

   #[test]
   fn test_service_file_has_description() {
       let service = generate_service_file(&default_options());
       assert!(service.contains("Description="));
   }

   #[test]
   fn test_service_file_has_exec_start() {
       let service = generate_service_file(&default_options());
       assert!(service.contains("ExecStart="));
       assert!(service.contains("rp start"));
   }
   ```

2. **Executable Path Detection**
   ```rust
   #[test]
   fn test_finds_current_executable() {
       let path = get_executable_path().unwrap();
       assert!(path.exists());
   }

   #[test]
   fn test_custom_executable_path() {
       let opts = ServiceOptions {
           executable_path: Some(PathBuf::from("/usr/local/bin/rp")),
           ..default_options()
       };
       let service = generate_service_file(&opts);
       assert!(service.contains("/usr/local/bin/rp"));
   }
   ```

3. **User/Group Configuration**
   ```rust
   #[test]
   fn test_default_user_is_root() {
       let service = generate_service_file(&default_options());
       // Default should either be root or not specify User (which means root)
   }

   #[test]
   fn test_custom_user_group() {
       let opts = ServiceOptions {
           user: Some("proxy".to_string()),
           group: Some("proxy".to_string()),
           ..default_options()
       };
       let service = generate_service_file(&opts);
       assert!(service.contains("User=proxy"));
       assert!(service.contains("Group=proxy"));
   }
   ```

4. **Security Hardening**
   ```rust
   #[test]
   fn test_hardened_has_protections() {
       let opts = ServiceOptions {
           hardened: true,
           ..default_options()
       };
       let service = generate_service_file(&opts);

       assert!(service.contains("ProtectSystem="));
       assert!(service.contains("ProtectHome="));
       assert!(service.contains("PrivateTmp="));
       assert!(service.contains("NoNewPrivileges="));
   }

   #[test]
   fn test_hardened_has_capability_restrictions() {
       let opts = ServiceOptions {
           hardened: true,
           ..default_options()
       };
       let service = generate_service_file(&opts);

       assert!(service.contains("CapabilityBoundingSet="));
   }

   #[test]
   fn test_non_hardened_minimal() {
       let opts = ServiceOptions {
           hardened: false,
           ..default_options()
       };
       let service = generate_service_file(&opts);

       // Should not have aggressive restrictions
       assert!(!service.contains("ProtectSystem=strict"));
   }
   ```

5. **Config Path Configuration**
   ```rust
   #[test]
   fn test_config_path_in_exec() {
       let opts = ServiceOptions {
           config_path: Some(PathBuf::from("/etc/rp/config.toml")),
           ..default_options()
       };
       let service = generate_service_file(&opts);
       assert!(service.contains("--config /etc/rp/config.toml") ||
               service.contains("-c /etc/rp/config.toml"));
   }
   ```

6. **Reload Configuration**
   ```rust
   #[test]
   fn test_has_exec_reload() {
       let service = generate_service_file(&default_options());
       assert!(service.contains("ExecReload="));
   }
   ```

7. **Logging Configuration**
   ```rust
   #[test]
   fn test_logging_to_journal() {
       let service = generate_service_file(&default_options());
       assert!(service.contains("StandardOutput=journal") ||
               service.contains("StandardOutput=syslog"));
       assert!(service.contains("SyslogIdentifier="));
   }
   ```

