```rust
#[test]
fn test_validate_service_file_syntax() {
    let service = generate_service_file(&default_options());

    // Basic INI format validation
    for line in service.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') || line.starts_with('[') {
            continue;
        }
        assert!(line.contains('='), "Invalid line: {}", line);
    }
}

#[test]
fn test_no_placeholder_left() {
    let service = generate_service_file(&default_options());
    assert!(!service.contains("{{"), "Unresolved placeholder in service file");
    assert!(!service.contains("}}"), "Unresolved placeholder in service file");
}
```

